@RestController
@RequestMapping("/api/v1/orders")
@Validated
public class OrderController {

    // @PreAuthorize — checked before method executes
    @GetMapping
    @PreAuthorize("hasAnyRole('USER', 'ADMIN')")
    public Page<OrderDto> getMyOrders(
            Authentication auth,
            Pageable pageable) {
        String userId = auth.getName(); // from JWT sub claim
        return orderService.findByUser(userId, pageable);
    }

    @PostMapping
    @PreAuthorize("hasRole('USER')")
    public ResponseEntity<OrderDto> createOrder(
            @RequestBody @Valid CreateOrderRequest req,
            Authentication auth) {
        // Validate user can only create orders for themselves
        if (!req.getUserId().equals(auth.getName())) {
            throw new AccessDeniedException("Cannot create order for other users");
        }
        return ResponseEntity.ok(orderService.create(req));
    }

    @DeleteMapping("/{id}")
    @PreAuthorize("hasRole('ADMIN') or @orderSecurityService.isOwner(#id, authentication)")
    public void delete(@PathVariable Long id) {
        orderService.delete(id);
    }
}

